def safe_divide(items, divisor):
    # Return empty list for invalid inputs
    if items is None or divisor == 0:
        return []
    # Ensure items is iterable and all elements are numeric (int or float)
    if not hasattr(items, '__iter__'):
        return []
    result = []
    for item in items:
        # Reject non-numeric items (including None, strings, etc.)
        if not isinstance(item, (int, float)):
            return []
        result.append(item / divisor)
    return result
