import ast
import operator

def evaluate_expression(expr):
    """Evaluate a mathematical expression and return the numeric result.
    Supports +, -, *, / and parentheses.
    Uses AST-based evaluation to prevent arbitrary code execution.
    """
    try:
        tree = ast.parse(expr, mode='eval')
    except SyntaxError:
        raise ValueError(f"Invalid expression: {expr}")

    return _eval_node(tree.body)

def _eval_node(node):
    """Recursively evaluate an AST node, allowing only safe operations."""
    if isinstance(node, ast.Constant):
        if isinstance(node.value, (int, float)):
            return node.value
        raise ValueError("Unsupported constant type")

    if isinstance(node, ast.UnaryOp):
        if isinstance(node.op, ast.USub):
            return -_eval_node(node.operand)
        elif isinstance(node.op, ast.UAdd):
            return +_eval_node(node.operand)
        else:
            raise ValueError("Unsupported unary operator")

    if isinstance(node, ast.BinOp):
        left = _eval_node(node.left)
        right = _eval_node(node.right)

        if isinstance(node.op, ast.Add):
            return operator.add(left, right)
        elif isinstance(node.op, ast.Sub):
            return operator.sub(left, right)
        elif isinstance(node.op, ast.Mult):
            return operator.mul(left, right)
        elif isinstance(node.op, ast.Div):
            # Use truediv to match typical float division behavior
            return operator.truediv(left, right)
        else:
            raise ValueError("Unsupported binary operator")

    # Any other node type (e.g., Name, Call, etc.) is not allowed
    raise ValueError("Unsupported expression syntax")
